class Animal
{
public:
    void makeSound() { cout << "Some generic animal sound" << endl; }
};

class Dog : public Animal
{
public:
    void makeSound() { cout << "Woof!" << endl; }
};

Animal *a = new Dog();
a->makeSound(); // prints Animal's version — NOT what we wanted

class Animal
{
public:
    virtual void makeSound() // mark it virtual in the BASE class
    {
        cout << "Some generic animal sound" << endl;
    }
};

class Dog : public Animal
{
public:
    void makeSound() override // override here confirms it matches
    {
        cout << "Woof!" << endl;
    }
};

#include <iostream>

using namespace std;

class Animal
{
public:
    virtual void makeSound()
    {
        cout << "Some generic animal sound" << endl;
    }
};

class Dog : public Animal
{
public:
    void makeSound() override
    {
        cout << "Woof!" << endl;
    }
};

int main()
{
    Animal *a = new Dog();

    a->makeSound();

    delete a;

    return 0;
}

#include <iostream>

using namespace std;

class Animal
{
public:
    virtual ~Animal() // virtual destructor
    {
        cout << "Animal destroyed" << endl;
    }
};

class Dog : public Animal
{
public:
    ~Dog()
    {
        cout << "Dog destroyed" << endl;
    }
};

int main()
{
    Animal *a = new Dog();

    delete a; // with a virtual destructor, BOTH destructors run, correctly

    return 0;
}

